// Same as StudentForm but with CV upload
export default function InstructorForm() {
    const { handleSignup, isLoading, isError, error } = useSignup();
  
    const onSubmit = (e) => {
      e.preventDefault();
      const formData = new FormData(e.target);
      const data = Object.fromEntries(formData);
      handleSignup({ ...data, role: 'instructor' });
    };
  
    return (
      <form onSubmit={onSubmit} className="space-y-4">
        {/* Same fields as Student + CV */}
        <input type="text" name="name" placeholder="Enter your full name" required className="input-field" />
        <input type="email" name="email" placeholder="Enter your email" required className="input-field" />
        <input type="tel" name="phone" placeholder="Enter your phone number" required className="input-field" />
        <input type="text" name="birthPlace" placeholder="Enter your place of birth" required className="input-field" />
        <input type="date" name="birthDate" required className="input-field" />
  
        <div className="relative">
          <input type="file" name="cv" accept=".pdf,.doc,.docx" required className="input-field file:hidden" />
          <button type="button" className="absolute right-3 top-1/2 -translate-y-1/2 bg-gray-100 dark:bg-gray-700 px-3 py-1 text-sm rounded">
            Browse
          </button>
        </div>
  
        <button type="submit" disabled={isLoading} className="btn-primary w-full">
          {isLoading ? 'Submitting...' : 'Apply as Instructor'}
        </button>
        {isError && <p className="text-red-500 text-sm text-center">{error}</p>}
      </form>
    );
  }
